sql:
SELECT area_id, population_count
FROM area_population
WHERE year = 2022;

SELECT SUM(population_count) AS total_population
FROM area_population
WHERE area_id = '1' AND year = 2023;

SELECT COUNT(image_id) AS total_images
  FROM area_images
  WHERE area_id = '1';

SELECT area_id, MAX(last_updated) AS latest_update
FROM areas
GROUP BY area_id;

external_knowledge:
; land area refers to the total area covered by land within each area's boundaries; 
; access events could refer to the number of times data about these areas has been accessed or retrieved; 
; the ranking is done in descending order, meaning areas with the highest population, largest land area, and most access events are listed first.

sql:
SELECT region_name
FROM region_mapping
WHERE area_id = '1';

SELECT MAX(value) AS largest_land_area
FROM area_statistics
WHERE area_id = '0' AND statistic_type = 'Land Area';

SELECT MAX(year) AS latest_year
FROM area_population
WHERE area_id = '1';

SELECT AVG(population_density) AS avg_density
FROM areas
WHERE area_id = '1';

SELECT region_name
FROM region_mapping
WHERE region_id = 1;
